sql:
SELECT name
FROM playlists
WHERE popularity = (SELECT MAX(popularity) FROM playlists);

SELECT user_id, COUNT(*) AS number_of_dislikes
FROM dislikes
GROUP BY user_id;

SELECT DISTINCT u.username
FROM users u
JOIN dislikes d ON u.user_id = d.user_id;

SELECT COUNT(*) AS number_of_dislikes
FROM dislikes
WHERE track_id = 1;

SELECT COUNT(*) AS total_likes
FROM likes
WHERE user_id = 1;

SELECT COUNT(*) AS total_likes
FROM likes
WHERE track_id = 1;

SELECT AVG(popularity) AS avg_playlist_popularity
FROM playlists
WHERE explicit = 0;

SELECT AVG(track_like_count) AS avg_track_likes
FROM (
    SELECT l.track_id, COUNT(l.user_id) AS track_like_count
    FROM likes l
    INNER JOIN (
        SELECT DISTINCT user_id
        FROM dislikes
    ) AS disliked_users ON l.user_id = disliked_users.user_id
    GROUP BY l.track_id
) AS liked_tracks;

SELECT title, artist, album
FROM tracks
WHERE track_id IN (SELECT track_id FROM likes);

external_knowledge:
The general feeling of a playlist is determined by the likes and dislikes of its tracks; 
A playlist with more likes than dislikes is considered 'Liked'; 
A playlist with more dislikes than likes is considered 'Disliked'; 
A playlist with an equal number of likes and dislikes is considered 'Neutral'.

Family-friendly playlists refer to playlists that do not contain explicit content (i.e., explicit = 0); 
Large following refers to playlists with more than 1000 followers;
Energetic refers to tracks with energy scores > 0.5;
Make you want to get up and dance refers to tracks with danceability scores > 0.6.
